#include "jsonConverter.hpp"
#include <stdexcept>

// Serialize an optional value: skip key when nullopt, emit value otherwise.
template <typename T>
static void opt_to_json(nlohmann::json &j, const char *key, const std::optional<T> &v)
{
  if (v.has_value())
    j[key] = *v;
}

// Deserialize an optional value: leave nullopt when key absent.
template <typename T>
static void opt_from_json(const nlohmann::json &j, const char *key, std::optional<T> &v)
{
  auto it = j.find(key);
  if (it != j.end() && !it->is_null())
    v = it->get<T>();
  else
    v = std::nullopt;
}

